from dataclasses import dataclass, field

@dataclass
class AutonomyTracker:
    """
    Tracks error rate and enforces promotion and demotion thresholds.
    """
    current_level: int = 0
    # Thresholds: (promote if error_rate below, demote if error_rate above)
    thresholds: dict = field(default_factory=lambda: {
        0: (0.02, 0.05),   # promote <2%, demote >5%
        1: (0.01, 0.02),
        2: (0.005, 0.01),
        3: (0.002, 0.005),
    })
    _total: int = 0
    _errors: int = 0
    _window: int = 500     # rolling window size

    def record(self, was_error: bool):
        self._total += 1
        if was_error:
            self._errors += 1
        # Simple rolling approximation: decay older counts
        if self._total > self._window:
            self._total = self._window
            self._errors = min(self._errors, self._window)

    @property
    def error_rate(self) -> float:
        return self._errors / self._total if self._total > 0 else 0.0

    def check_promotion(self) -> str | None:
        """Returns 'promote', 'demote', or None."""
        if self._total < 200:
            return None  # not enough data
        promote_threshold, demote_threshold = self.thresholds.get(
            self.current_level, (0.002, 0.005)
        )
        if self.error_rate < promote_threshold and self.current_level < 4:
            return "promote"
        if self.error_rate > demote_threshold and self.current_level > 0:
            return "demote"
        return None

    def apply_check(self) -> str:
        action = self.check_promotion()
        if action == "promote":
            self.current_level += 1
            return f"Promoted to level {self.current_level} (error_rate={self.error_rate:.3f})"
        if action == "demote":
            self.current_level -= 1
            return f"Demoted to level {self.current_level} (error_rate={self.error_rate:.3f})"
        return f"No change. Level={self.current_level}, error_rate={self.error_rate:.3f}"

tracker = AutonomyTracker()
for i in range(300):
    tracker.record(was_error=(i % 100 == 0))  # 1% error rate
print(tracker.apply_check())
# After 300 actions at 1% error rate, level 0 -> 1 threshold is 2% -> promotes
